command:example.dev:code:
$deck | Add-TerminalSlide -Title 'Decision' -Content {
  Add-SlideBox `
    -Text 'Ship behind a feature flag.' `
    -RevealStep 1
} | Out-Null

$deck | Add-TerminalSlide -Title 'Benefits' -Content {
  Add-SlideBullet 'Version presentations with code'
  Add-SlideBullet 'Present from any terminal' `
    -RevealStep 1
} | Out-Null

$data = @(
  [pscustomobject]@{ Label = 'Build'; Value = 82 }
  [pscustomobject]@{ Label = 'Test'; Value = 96 }
)
$deck | Add-TerminalSlide -Title 'Pipeline' -Content {
  Add-SlideChart -Data $data `
    -ChartType HorizontalBar `
    -Title 'Success rate'
} | Out-Null

$deck | Add-TerminalSlide -Title 'Flow' -Content {
  Add-SlideDiagram -Content {
    Add-SlideDiagramNode -Id source -Label 'Source'
    Add-SlideDiagramNode -Id deploy -Label 'Deploy'
    Add-SlideDiagramEdge -From source -To deploy -Label 'publish'
  }
} | Out-Null

$deck | Add-TerminalSlide -Title 'Request flow' -Content {
  Add-SlideDiagram -Content {
    Add-SlideDiagramNode -Id client -Label 'Client'
    Add-SlideDiagramNode -Id api -Label 'API'
    Add-SlideDiagramEdge -From client -To api -Label 'HTTPS'
  }
} | Out-Null

$deck | Add-TerminalSlide -Title 'Components' -Content {
  Add-SlideDiagram -Content {
    Add-SlideDiagramNode -Id api -Label 'API'
    Add-SlideDiagramNode -Id data -Label 'Data store'
    Add-SlideDiagramEdge -From api -To data
  }
} | Out-Null

$deck | Add-TerminalSlide -Title 'Roadmap' -Content {
  Add-SlideText 'Three milestones lead to launch.'
  Add-SlideNotes `
    'Pause here and ask for questions.'
} | Out-Null

$deck | Add-TerminalSlide -Title 'Principle' -Layout Quote -Content {
  Add-SlideQuote `
    -Text 'Make the change easy, then make the easy change.' `
    -Attribution 'Kent Beck' `
    -Region Quote
} | Out-Null

$deck | Add-TerminalSlide -Title 'Opening' -Content {
  Add-SlideSubtitle 'A PowerShell-native deck' `
    -RevealStep 1
} | Out-Null

$rows = @(
  [pscustomobject]@{ Service = 'API'; Status = 'Healthy' }
  [pscustomobject]@{ Service = 'Worker'; Status = 'Healthy' }
)
$deck | Add-TerminalSlide -Title 'Services' -Content {
  Add-SlideTable -Data $rows -Border
} | Out-Null

$deck | Add-TerminalSlide -Title 'Context' -Content {
  Add-SlideText `
    'TerminalSlides keeps presentations beside the code.' `
    -Alignment Center
} | Out-Null

$deck | Add-TerminalSlide -Title 'Opening' -Content {
  Add-SlideTitle 'Build. Present. Automate.' `
    -Alignment Center
} | Out-Null
